import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.map.js";
import fetchWithAuth from '@/utils/fetchWithAuth';
import FloatingSaveButton from '@/components/FloatingSaveButton.vue';
export default {
  components: {
    FloatingSaveButton
  },
  data() {
    return {
      settings: {
        telemetry: {},
        randomImageAPI: {},
        cloudflareApiToken: {},
        webDAV: {},
        publicBrowse: {}
      },
      aiSettings: createDefaultAISettings(),
      directoryMode: 'all',
      directoryTree: [],
      directoryTreeProps: {
        label: 'name',
        value: 'path',
        children: 'children'
      },
      taggingModels: ['SmilingWolf/wd-swinv2-tagger-v3', 'SmilingWolf/wd-convnext-tagger-v3', 'SmilingWolf/wd-vit-tagger-v3', 'SmilingWolf/wd-vit-large-tagger-v3'],
      tagging: false,
      manualProgress: {
        processed: 0,
        total: 0
      },
      availableChannels: {},
      // 可用渠道列表
      // 加载状态
      loading: true
    };
  },
  computed: {
    // WebDAV 当前渠道类型对应的渠道列表
    webdavChannelList() {
      const channelType = this.settings.webDAV?.uploadChannel;
      return channelType ? this.availableChannels[channelType] || [] : [];
    },
    manualProgressText() {
      return this.$t('sysOthers.taggingProgress', this.manualProgress);
    }
  },
  watch: {
    'settings.webDAV.uploadChannel'() {
      // 切换渠道类型时清空指定的渠道名称
      if (this.settings.webDAV) {
        this.settings.webDAV.channelName = '';
      }
    }
  },
  methods: {
    async saveSettings() {
      if (!this.aiSettings.providers.wdTagger.endpoint && this.aiSettings.capabilities.tagging.enabled) {
        this.$message.warning(this.$t('sysOthers.spaceUrlRequired'));
        return;
      }
      if (this.directoryMode === 'all') {
        this.aiSettings.capabilities.tagging.targetDirectories = [];
      }
      this.aiSettings.providers.wdTagger.requestFormat = 'multipart';
      this.aiSettings.enabled = Boolean(this.aiSettings.providers.wdTagger.endpoint);
      const [othersResponse, aiResponse] = await Promise.all([fetchWithAuth('/api/manage/sysConfig/others', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(this.settings)
      }), fetchWithAuth('/api/manage/sysConfig/ai', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(this.aiSettings)
      })]);
      if (!othersResponse.ok || !aiResponse.ok) throw new Error('Failed to save settings');
      this.aiSettings = normalizeAISettings(await aiResponse.json());
      this.$message.success(this.$t('sysOthers.settingsSaved'));
    },
    async fetchAvailableChannels() {
      try {
        const response = await fetchWithAuth('/api/channels');
        if (response.ok) {
          this.availableChannels = await response.json();
        }
      } catch (error) {
        console.error('Failed to fetch available channels:', error);
      }
    },
    async fetchDirectoryTree() {
      try {
        const response = await fetchWithAuth('/api/directoryTree');
        if (!response.ok) return;
        const data = await response.json();
        this.directoryTree = normalizeDirectoryNodes(data.tree?.children || []);
      } catch (error) {
        console.error('Failed to fetch directory tree:', error);
      }
    },
    async startManualTagging() {
      if (!this.aiSettings.providers.wdTagger.endpoint) {
        this.$message.warning(this.$t('sysOthers.spaceUrlRequired'));
        return;
      }
      if (this.directoryMode === 'selected' && !this.aiSettings.capabilities.tagging.targetDirectories.length) {
        this.$message.warning(this.$t('sysOthers.selectDirectories'));
        return;
      }
      this.tagging = true;
      this.manualProgress = {
        processed: 0,
        total: 0
      };
      let offset = 0;
      try {
        this.aiSettings.enabled = true;
        this.aiSettings.providers.wdTagger.requestFormat = 'multipart';
        const saveResponse = await fetchWithAuth('/api/manage/sysConfig/ai', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify(this.aiSettings)
        });
        if (!saveResponse.ok) throw new Error(this.$t('sysOthers.taggingFailed'));
        this.aiSettings = normalizeAISettings(await saveResponse.json());
        do {
          const response = await fetchWithAuth('/api/manage/ai/tag', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json'
            },
            body: JSON.stringify({
              offset,
              limit: 3,
              directories: this.directoryMode === 'all' ? [] : this.aiSettings.capabilities.tagging.targetDirectories
            })
          });
          const result = await response.json();
          if (!response.ok) throw new Error(result.message || result.error);
          this.manualProgress = {
            processed: offset + result.processed,
            total: result.total
          };
          offset = result.nextOffset;
        } while (offset !== null);
        this.$message.success(this.$t('sysOthers.taggingCompleted', this.manualProgress));
      } catch (error) {
        this.$message.error(error.message || this.$t('sysOthers.taggingFailed'));
      } finally {
        this.tagging = false;
      }
    }
  },
  mounted() {
    this.loading = true;
    // 获取上传设置
    Promise.all([fetchWithAuth('/api/manage/sysConfig/others').then(response => response.json()), fetchWithAuth('/api/manage/sysConfig/ai').then(response => response.json())]).then(([settings, aiSettings]) => {
      this.settings = settings;
      this.aiSettings = normalizeAISettings(aiSettings);
      this.directoryMode = this.aiSettings.capabilities.tagging.targetDirectories.length ? 'selected' : 'all';
    }).finally(() => {
      this.loading = false;
    });
    // 获取可用渠道列表
    this.fetchAvailableChannels();
    this.fetchDirectoryTree();
  }
};
function createDefaultAISettings() {
  return {
    enabled: false,
    timeoutMs: 30000,
    capabilities: {
      tagging: {
        enabled: false,
        provider: 'wd_tagger',
        targetDirectories: []
      }
    },
    providers: {
      wdTagger: {
        endpoint: '',
        model: 'SmilingWolf/wd-swinv2-tagger-v3',
        threshold: 0.35,
        characterThreshold: 0.85,
        requestFormat: 'multipart',
        fileField: 'image'
      }
    }
  };
}
function normalizeAISettings(settings = {}) {
  const defaults = createDefaultAISettings();
  return {
    ...defaults,
    ...settings,
    capabilities: {
      tagging: {
        ...defaults.capabilities.tagging,
        ...settings.capabilities?.tagging
      }
    },
    providers: {
      wdTagger: {
        ...defaults.providers.wdTagger,
        ...settings.providers?.wdTagger
      }
    }
  };
}
function normalizeDirectoryNodes(nodes) {
  return nodes.map(node => ({
    ...node,
    path: String(node.path || '').replace(/^\/+|\/+$/g, ''),
    children: normalizeDirectoryNodes(node.children || [])
  }));
}